//! The Ulysses pact — an agent cryptographically swears its oath at spawn.
//!
//! monster-swarm already mints each subagent's keypair (a fresh `did:key` + a
//! 0600 keyfile) at spawn. This module uses *that* key to make the agent sign
//! its own oath into a UCAN **oath-token**: a self-signed promise the agent
//! hands to monster-guard, which verifies the signature at admission. The agent
//! ties itself to the mast with its own signature — `iss = aud = agent DID`
//! (Ulysses: the swearer and the bound are one).
//!
//! A signed oath-token is a UCAN with:
//!   - `iss = aud = <agent DID>` (the Ulysses self-binding),
//!   - `att = [Capability{ can: "oath/uphold", with: "agent:self:<id>" }]`,
//!   - `fct = <oath terms JSON>` — the same `{ oath, max_caps, ttl_max_secs?,
//!     sworn_by? }` contract monster-guard's oathspec uses, so the terms the
//!     grant is admitted under are carried, signed, by the token, and
//!   - signed by the agent's own keypair.
//!
//! Co-signed (spawner-imposed → agent-accepted): when the spawner hands down its
//! own oath-token, the agent COUNTER-SIGNS by minting an acceptance token that
//! carries the imposed token in `prf` (proofs). `verify_chain` then walks the
//! chain spawner-imposed -> agent-accepted.

use a0n_auth::ucan::issue;
use a0n_auth::{Capability, IssueOptions, Keypair};

/// The capability an oath-token grants: the sworn duty to uphold the oath, over
/// the agent's own self-resource. Ulysses binds himself, so `with` is `self`.
pub const OATH_CAN: &str = "oath/uphold";

/// The self-resource an oath-token is sworn over: `agent:self:<id>`.
pub fn oath_resource(id: &str) -> String {
    format!("agent:self:{id}")
}

/// The oath/uphold capability for agent `id`, over its own self-resource.
pub fn oath_capability(id: &str) -> Capability {
    Capability {
        can: OATH_CAN.to_string(),
        with: oath_resource(id),
        constraints: None,
    }
}

/// Shape detection: is this string a UCAN oath-token (already signed), or RAW
/// oath terms JSON the agent must still swear?
///
/// A UCAN is `header.payload.signature` — three base64url dot-segments, no
/// whitespace. Raw oath terms are a JSON object (`{ ... }`). We treat anything
/// that is exactly three non-empty, whitespace-free dot-segments as a token;
/// everything else is raw terms (or a path the caller already resolved).
pub fn is_oath_token(s: &str) -> bool {
    let t = s.trim();
    if t.is_empty() || t.contains(char::is_whitespace) {
        return false;
    }
    let parts: Vec<&str> = t.split('.').collect();
    parts.len() == 3 && parts.iter().all(|p| !p.is_empty())
}

/// Mint a Ulysses self-signed oath-token: the agent swears `terms` with its OWN
/// keypair, `iss = aud = agent DID`. `terms` is the raw oath JSON (validated by
/// the caller / monster-guard); it is bound verbatim as the token's `fct`. When
/// `proof` is `Some`, it is carried in `prf` so the chain reads spawner-imposed
/// -> agent-accepted (the co-signed case).
pub fn mint_self_oath_token(
    agent_kp: &Keypair,
    id: &str,
    terms: serde_json::Value,
    ttl_secs: i64,
    proof: Option<String>,
) -> Result<String, String> {
    let cap = oath_capability(id);
    let opts = IssueOptions {
        facts: Some(terms),
        proofs: proof.into_iter().collect(),
        ..Default::default()
    };
    issue(agent_kp, agent_kp.did(), &[cap], ttl_secs, &opts).map_err(|e| e.to_string())
}

/// Mint a spawner-IMPOSED oath-token: the spawner (`spawner_kp`) imposes the
/// oath on the agent by issuing a token whose `aud = agent_did`. This is the
/// parent the agent counter-signs (its acceptance leaf's `iss = agent_did`
/// matches this token's `aud`, so `verify_chain` walks imposed -> accepted). The
/// terms are bound as `fct`; the cap is the same oath/uphold over the agent's
/// self-resource. Used by spawners and in tests; the swarm's spawn path
/// counter-signs whatever imposed token it is handed.
pub fn mint_imposed_oath_token(
    spawner_kp: &Keypair,
    agent_did: &str,
    id: &str,
    terms: serde_json::Value,
    ttl_secs: i64,
) -> Result<String, String> {
    let cap = oath_capability(id);
    let opts = IssueOptions {
        facts: Some(terms),
        ..Default::default()
    };
    issue(spawner_kp, agent_did, &[cap], ttl_secs, &opts).map_err(|e| e.to_string())
}

/// Parse + lightly validate raw oath terms JSON. The full conduct-bound checks
/// (caps subset, ttl ceiling) are monster-guard's at admission; here we only
/// require a well-formed object with a non-empty `oath` so we never sign garbage
/// into the mast. Returns the parsed terms to bind as `fct`.
pub fn parse_terms(text: &str) -> Result<serde_json::Value, String> {
    let v: serde_json::Value =
        serde_json::from_str(text).map_err(|e| format!("invalid oath terms JSON: {e}"))?;
    if !v.is_object() {
        return Err("oath terms must be a JSON object".to_string());
    }
    let oath_ok = v
        .get("oath")
        .and_then(|o| o.as_str())
        .map(|s| !s.trim().is_empty())
        .unwrap_or(false);
    if !oath_ok {
        return Err("oath terms: 'oath' commitment string must be present and non-empty".to_string());
    }
    Ok(v)
}

#[cfg(test)]
mod tests {
    use super::*;
    use a0n_auth::verify_chain;

    fn terms() -> serde_json::Value {
        serde_json::json!({
            "oath": "I serve the spawner's intent, stay within my caps, and do not exfiltrate.",
            "max_caps": ["net"],
            "ttl_max_secs": 3600
        })
    }

    #[test]
    fn token_shape_detection() {
        // Raw terms JSON is NOT a token.
        assert!(!is_oath_token(r#"{ "oath": "x", "max_caps": ["net"] }"#));
        // A path is not a token.
        assert!(!is_oath_token("oaths/no-exfil.oathspec"));
        assert!(!is_oath_token(""));
        // A real minted token is three non-empty dot-segments, no whitespace.
        let kp = Keypair::generate();
        let tok = mint_self_oath_token(&kp, "a", terms(), 3600, None).unwrap();
        assert!(is_oath_token(&tok), "minted token must be detected as a token");
        // Two segments is not a token.
        assert!(!is_oath_token("aa.bb"));
        assert!(!is_oath_token("aa..cc"));
    }

    #[test]
    fn ulysses_self_signed_token_verifies_and_carries_terms() {
        let kp = Keypair::generate();
        let id = "ulysses";
        let tok = mint_self_oath_token(&kp, id, terms(), 3600, None).expect("mint");

        // The chain is valid and rooted at the agent itself (no proof).
        let res = verify_chain(&tok, None, None);
        assert!(res.valid, "self-signed oath-token must verify: {:?}", res.error);
        assert_eq!(res.root_issuer.as_deref(), Some(kp.did()));

        let leaf = res.chain.first().expect("leaf");
        // Ulysses: the swearer ties HIMSELF to the mast — iss == aud == agent DID.
        assert_eq!(leaf.iss, kp.did());
        assert_eq!(leaf.aud, kp.did());
        assert_eq!(leaf.iss, leaf.aud, "ulysses self-binding: iss == aud");
        // The oath/uphold capability over the agent's own self-resource.
        assert_eq!(leaf.att.len(), 1);
        assert_eq!(leaf.att[0].can, OATH_CAN);
        assert_eq!(leaf.att[0].with, oath_resource(id));
        // The leaf carries the exact terms as fct.
        assert_eq!(leaf.fct.as_ref().expect("fct"), &terms());
    }

    #[test]
    fn cosigned_token_chains_imposed_then_accepted() {
        // The spawner IMPOSES an oath-token addressed to the agent (aud = agent
        // DID); the agent counter-signs by minting an acceptance token (iss = aud
        // = agent DID, the Ulysses self-binding) that carries the imposed token as
        // proof. The chain reads spawner-imposed -> agent-accepted: the leaf's iss
        // (agent) matches the imposed token's aud (agent), so it links.
        let agent = Keypair::generate();
        let spawner = Keypair::generate();
        let imposed = mint_imposed_oath_token(&spawner, agent.did(), "agent", terms(), 3600)
            .expect("spawner imposes oath on the agent");

        let accepted = mint_self_oath_token(&agent, "agent", terms(), 3600, Some(imposed.clone()))
            .expect("agent counter-signs");

        let res = verify_chain(&accepted, None, None);
        assert!(res.valid, "co-signed chain must verify: {:?}", res.error);
        // leaf = agent-accepted, root = spawner-imposed.
        assert_eq!(res.chain.len(), 2, "imposed -> accepted is a two-link chain");
        assert_eq!(res.chain[0].iss, agent.did(), "leaf issuer is the agent");
        assert_eq!(res.root_issuer.as_deref(), Some(spawner.did()), "root is the spawner");
    }

    #[test]
    fn parse_terms_rejects_garbage_accepts_well_formed() {
        assert!(parse_terms("not json").is_err());
        assert!(parse_terms("[1,2,3]").is_err(), "array is not an oath object");
        assert!(parse_terms(r#"{ "max_caps": ["net"] }"#).is_err(), "missing oath");
        assert!(parse_terms(r#"{ "oath": "  ", "max_caps": ["net"] }"#).is_err(), "blank oath");
        let v = parse_terms(r#"{ "oath": "stay bounded", "max_caps": ["net"] }"#).expect("ok");
        assert_eq!(v["oath"], "stay bounded");
    }
}
